const Transition = () => {
    const [state, setState] = useState('loading')

    return (
        <div
            style={{ display: 'flex', flexDirection: 'column', gap: 16, alignItems: 'center' }}>
            <TicketWidget
                value="10,09%"
                direction="down"
                pulse={false}
                widthDur={220}
                fadeDur={180}
                charStagger={20}
                blurAmt={4}
                digitInterval={800}
                digitJitter={300}
                state={state} />
            <div style={{ display: 'flex', gap: 8 }}>
                <button onClick={() => setState('loading')}>Reset</button>
                <button onClick={() => setState('loaded')}>Load now</button>
            </div>
        </div>
    );
};

const AutoLoop = () => {
    const [state, setState] = useState('loading')
    useEffect(() => {
      const id = setInterval(() => {
        setState(prev => (prev === 'loading' ? 'loaded' : 'loading'))
      }, 2500)
      return () => clearInterval(id)
    }, [])

    return (
        <TicketWidget
            value="10,09%"
            direction="down"
            pulse={false}
            widthDur={220}
            fadeDur={180}
            charStagger={20}
            blurAmt={4}
            digitInterval={800}
            digitJitter={300}
            state={state} />
    );
};

const InlineInText = (args) => {
  const [state, setState] = useState('loading')
  useEffect(() => {
    const id = setTimeout(() => setState('loaded'), 1200)
    return () => clearTimeout(id)
  }, [])
  const tw = (props) => <TicketWidget {...args} {...props} state={state} />
  return (
    <div style={{ maxWidth: 720, padding: 24, fontFamily: "'SB Sans Text', system-ui, sans-serif" }}>
      <ul
        style={{
          listStyle: 'disc',
          paddingLeft: 24,
          fontFamily: 'var(--font-text-m-regular-family)',
          fontSize: 'var(--font-text-m-regular-size)',
          fontWeight: 'var(--font-text-m-regular-weight)',
          lineHeight: 'var(--font-text-m-regular-line-height)',
          letterSpacing: 'var(--font-text-m-regular-letter-spacing)',
          color: 'var(--color-text-standard-general-primary)',
          margin: 0,
        }}
      >
        <li>
          <strong>Лидеры роста:</strong> Совкомфлот{' '}
          {tw({ direction: 'up', value: '3,01%', iconSrc: ICON_SKF })}
          {' '}восстановил объёмы перевозок, а Северсталь{' '}
          {tw({ direction: 'up', value: '2,65%', iconSrc: ICON_SEVERSTAL })}
          {' '}выигрывает от стабилизации цен на сталь.
        </li>
        <li style={{ marginTop: 16 }}>
          <strong>Лидеры падения:</strong> Новатэк{' '}
          {tw({ direction: 'down', value: '2,32%', iconSrc: ICON_NOVATEK })}
          {' '}упал на фоне коррекции в нефтегазовом секторе. ВТБ{' '}
          {tw({ direction: 'down', value: '2,12%', iconSrc: ICON_VTB })}
          {' '}под давлением после публикации отчета.{' '}
          <span style={{ color: 'var(--color-text-standard-general-tertiary)' }}>sbercib.ru +3</span>
        </li>
      </ul>
      <button
        style={{ marginTop: 24 }}
        onClick={() => setState(state === 'loading' ? 'loaded' : 'loading')}
      >
        Toggle state
      </button>
    </div>
  )
};

